// ESP32 WiFi Scanner
// ===================
// Scans for nearby WiFi networks and prints SSID, RSSI, and
// encryption type every 10 seconds. Blinks LED during scan.
//
// This feature is unique to ESP32 — not available on AVR Arduino.
//
// Circuit: GPIO2 -> 220R -> Blue LED -> GND (scan activity indicator)

#include <Arduino.h>
#include <WiFi.h>

const int LED_PIN = 2;
int scanCount = 0;

const char* encryptionTypeStr(wifi_auth_mode_t type) {
  switch (type) {
    case WIFI_AUTH_OPEN:            return "Open";
    case WIFI_AUTH_WEP:             return "WEP";
    case WIFI_AUTH_WPA_PSK:         return "WPA-PSK";
    case WIFI_AUTH_WPA2_PSK:        return "WPA2-PSK";
    case WIFI_AUTH_WPA_WPA2_PSK:    return "WPA/WPA2";
    case WIFI_AUTH_WPA2_ENTERPRISE: return "WPA2-ENT";
    default:                        return "Unknown";
  }
}

void setup() {
  Serial.begin(115200);
  pinMode(LED_PIN, OUTPUT);
  delay(300);

  Serial.println("========================");
  Serial.println("  ESP32 WiFi Scanner");
  Serial.println("========================");
  Serial.println();

  // Set WiFi to station mode (not AP)
  WiFi.mode(WIFI_STA);
  WiFi.disconnect();
  delay(100);

  Serial.println("WiFi initialized in station mode.");
  Serial.println("Scanning every 10 seconds...");
  Serial.println("---");
}

void loop() {
  scanCount++;
  digitalWrite(LED_PIN, HIGH);  // LED on during scan

  Serial.print("\n=== Scan #");
  Serial.print(scanCount);
  Serial.println(" ===");

  int numNetworks = WiFi.scanNetworks();

  digitalWrite(LED_PIN, LOW);   // LED off after scan

  if (numNetworks == 0) {
    Serial.println("No networks found.");
  } else {
    Serial.print(numNetworks);
    Serial.println(" network(s) found:\n");

    Serial.println("  #  | RSSI | Ch | Encryption  | SSID");
    Serial.println("-----+------+----+-------------+--------------------");

    for (int i = 0; i < numNetworks; i++) {
      // Formatted table output
      char line[120];
      snprintf(line, sizeof(line), "  %2d | %4d | %2d | %-11s | %s",
        i + 1,
        WiFi.RSSI(i),
        WiFi.channel(i),
        encryptionTypeStr(WiFi.encryptionType(i)),
        WiFi.SSID(i).c_str()
      );
      Serial.println(line);
    }
  }

  // Clean up scan results from memory
  WiFi.scanDelete();

  // Wait 10 seconds before next scan
  Serial.println("\nNext scan in 10 seconds...");
  delay(10000);
}
